mapper.select:
SELECT post_id, inst_id, post_code, name, remarks FROM sys_post WHERE is_deleted = 0
AND post_id = #{sysPostDTO.postId}
AND inst_id = #{sysPostDTO.instId}
AND post_id in (SELECT post_id FROM sys_post_user WHERE user_id = #{sysPostDTO.userId} AND is_deleted = 0)
AND name = #{sysPostDTO.name}
AND post_code = #{sysPostDTO.postCode}
